{
  "summary": "The extraction failed. While most header fields (company, subtotal, tax, total) were correctly identified, the date year does not match the gold label, and the line item extraction is highly inaccurate. The model merged multiple lines—specifically item descriptions and their associated unit price lines—into single entries, resulting in a significantly lower item count than the gold standard.",
  "failure_reasons": [
    "date_mismatch",
    "line_item_merging",
    "line_item_count_mismatch"
  ],
  "field_notes": {
    "date": "Predicted 'Jan 25, 2018' but gold label requires '2026-01-25'.",
    "address": "The model extracted an address, but the gold label expected null.",
    "line_items": "The model merged description lines with unit price lines (e.g., 'French Fries x 2' and '($2.50 each)') into single items, reducing the total count from 13 to 8."
  }
}
